SELECT ubh.id, ubh.user_id, ubh.artifact_id, ubh.browse_time AS browseTime,
       u.username, u.avatar_url AS userAvatar,
       a.title_zh AS artifactName, a.image_url AS artifactImage
FROM user_browse_history ubh
LEFT JOIN users u ON ubh.user_id = u.id
LEFT JOIN artifacts a ON ubh.artifact_id = a.id

    AND ubh.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')

    AND ubh.artifact_id = #{artifactId}

        AND ubh.browse_time >= #{startTime}


        AND ubh.browse_time <= #{endTime}


ORDER BY ubh.browse_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM user_browse_history ubh
LEFT JOIN users u ON ubh.user_id = u.id

    AND ubh.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')

    AND ubh.artifact_id = #{artifactId}

        AND ubh.browse_time >= #{startTime}


        AND ubh.browse_time <= #{endTime}
